def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about food into a single fluent sentence."""
    if not triples:
        return ""

    # ------------------------------------------------------------------
    # Normalise input to a list of (subject, predicate, object) tuples
    # ------------------------------------------------------------------
    norm = []
    for t in triples:
        if isinstance(t, Triple):
            s, p, o = t.subject, t.predicate, t.object
        else:
            try:
                s, p, o = t
            except Exception:
                continue
        s = str(s).strip()
        p = str(p).strip()
        o = str(o).strip().strip('"\'')

        norm.append((s, p, o))

    # ------------------------------------------------------------------
    # Helper that maps a single predicate to a short phrase
    # ------------------------------------------------------------------
    def phrase_for(subj: str, pred: str, obj: str) -> str:
        if pred == "country":
            return f"{subj} is from {obj}"
        if pred == "ingredient":
            return f"{subj} contains {obj}"
        if pred == "region":
            return f"{subj} is from the {obj} region"
        if pred == "division":
            return f"{subj} belongs to the {obj} division"
        if pred == "family":
            return f"{subj} is in the {obj} family"
        if pred == "order":
            return f"{subj} belongs to the {obj} order"
        if pred == "course":
            return f"{subj} is served as a {obj}"
        if pred == "mainIngredient":
            return f"The main ingredients of {subj} are {obj}"
        if pred == "dishVariation":
            return f"{subj} can be varied with {obj}"
        if pred == "leader":
            return f"The leader of {subj} is {obj}"
        if pred == "alternativeName":
            return f"{subj} is also known as {obj}"
        if pred in ("creatorOfDish", "creator"):
            return f"{subj} was created by {obj}"
        if pred in ("servingTemperature", "served"):
            return f"{subj} is served {obj}"
        if pred == "carbohydrate":
            return f"{subj} contains {obj} carbohydrates"
        if pred == "fat":
            return f"{subj} contains {obj} fat"
        if pred == "protein":
            return f"{subj} contains {obj} protein"
        if pred == "year":
            return f"{subj} was introduced in {obj}"
        if pred == "related":
            return f"{subj} is related to {obj}"
        if pred == "similarDish":
            return f"{subj} is similar to {obj}"
        if pred == "genus":
            return f"{subj} belongs to the genus {obj}"
        if pred == "language":
            return f"The language of {subj} is {obj}"
        if pred == "isPartOf":
            return f"{subj} is part of {obj}"
        if pred == "currency":
            return f"The currency of {subj} is {obj}"
        if pred == "demonym":
            return f"The people of {subj} are called {obj}"
        if pred == "capital":
            return f"The capital of {subj} is {obj}"
        if pred == "ethnicGroup":
            return f"The ethnic group of {subj} is {obj}"
        if pred == "foundationPlace":
            return f"{subj} was founded in {obj}"
        if pred == "officialLanguage":
            return f"The official language of {subj} is {obj}"
        if pred == "leaderTitle":
            return f"The leader title of {subj} is {obj}"
        if pred == "servingSize":
            return f"The serving size of {subj} is {obj}"
        if pred == "class":
            return f"{subj} belongs to the class {obj}"
        # fallback
        return f"{subj} {pred} {obj}"

    # ------------------------------------------------------------------
    # Group triples by their subject to build compact sentences
    # ------------------------------------------------------------------
    from collections import defaultdict
    groups = defaultdict(list)
    for s, p, o in norm:
        groups[s].append((p, o))

    subject_sentences = []
    for subj, rels in groups.items():
        parts = [phrase_for(subj, pred, obj) for pred, obj in rels]
        if len(parts) == 1:
            subject_sentences.append(parts[0])
        else:
            subject_sentences.append(", ".join(parts[:-1]) + ", and " + parts[-1])

    # ------------------------------------------------------------------
    # Combine all subject sentences into one final paragraph‑like sentence
    # ------------------------------------------------------------------
    if len(subject_sentences) == 1:
        return subject_sentences[0] + "."
    else:
        return " ".join(subject_sentences) + "."

# EVOLVE-BLOCK-END

